#include <vector>
#include <algorithm>

std::vector<int> filter_even(const std::vector<int>& nums) {
    std::vector<int> result;
    for (int n : nums) {
        if (n % 2 == 0) result.push_back(n);
    }
    return result;
}

#include <fstream>
#include <string>
#include <iostream>

void read_file(const std::string& path) {
    std::ifstream file(path);
    if (file.is_open()) {
        std::string line;
        while (std::getline(file, line)) {
            std::cout << line << '\n';
        }
    }
}

